package filestore

// Schema is the on-disk representation of a policy snapshot. It is intentionally
// flat and human-friendly so policy can be authored by hand or generated by an
// out-of-band export from the CRUD admin server.
//
// Identifiers default to deterministic values derived from their FQN when not
// supplied, so a minimal file only needs namespaces, attribute names, values,
// and (optionally) subject mappings.
type Schema struct {
	Namespaces            []NamespaceDef            `yaml:"namespaces" json:"namespaces"`
	Attributes            []AttributeDef            `yaml:"attributes" json:"attributes"`
	SubjectConditionSets  []SubjectConditionSetDef  `yaml:"subject_condition_sets" json:"subject_condition_sets"`
	SubjectMappings       []SubjectMappingDef       `yaml:"subject_mappings" json:"subject_mappings"`
	ResourceMappings      []ResourceMappingDef      `yaml:"resource_mappings" json:"resource_mappings"`
	ResourceMappingGroups []ResourceMappingGroupDef `yaml:"resource_mapping_groups" json:"resource_mapping_groups"`
	KeyAccessServers      []KeyAccessServerDef      `yaml:"key_access_servers" json:"key_access_servers"`
	RegisteredResources   []RegisteredResourceDef   `yaml:"registered_resources" json:"registered_resources"`
	Obligations           []ObligationDef           `yaml:"obligations" json:"obligations"`
}

type NamespaceDef struct {
	ID   string `yaml:"id" json:"id"`
	Name string `yaml:"name" json:"name"`
	FQN  string `yaml:"fqn" json:"fqn"`
}

type AttributeDef struct {
	ID        string          `yaml:"id" json:"id"`
	Namespace string          `yaml:"namespace" json:"namespace"`
	Name      string          `yaml:"name" json:"name"`
	Rule      string          `yaml:"rule" json:"rule"` // allOf|anyOf|hierarchy
	Values    []AttrValueDef  `yaml:"values" json:"values"`
	Grants    []KasReferenceD `yaml:"grants" json:"grants"`
}

type AttrValueDef struct {
	ID     string          `yaml:"id" json:"id"`
	Value  string          `yaml:"value" json:"value"`
	Grants []KasReferenceD `yaml:"grants" json:"grants"`
}

type SubjectMappingDef struct {
	ID                  string        `yaml:"id" json:"id"`
	AttributeValueFQN   string        `yaml:"attribute_value_fqn" json:"attribute_value_fqn"`
	SubjectConditionSet string        `yaml:"subject_condition_set" json:"subject_condition_set"`
	InlineConditionSet  *InlineSCSDef `yaml:"inline_condition_set,omitempty" json:"inline_condition_set,omitempty"`
	Actions             []ActionRef   `yaml:"actions" json:"actions"`
}

type ActionRef struct {
	Name     string `yaml:"name" json:"name"`
	Standard string `yaml:"standard" json:"standard"` // optional STANDARD_ACTION_DECRYPT|TRANSMIT
}

type SubjectConditionSetDef struct {
	ID          string          `yaml:"id" json:"id"`
	SubjectSets []SubjectSetDef `yaml:"subject_sets" json:"subject_sets"`
}

type InlineSCSDef struct {
	SubjectSets []SubjectSetDef `yaml:"subject_sets" json:"subject_sets"`
}

type SubjectSetDef struct {
	ConditionGroups []ConditionGroupDef `yaml:"condition_groups" json:"condition_groups"`
}

type ConditionGroupDef struct {
	BooleanOperator string         `yaml:"boolean_operator" json:"boolean_operator"` // AND|OR
	Conditions      []ConditionDef `yaml:"conditions" json:"conditions"`
}

type ConditionDef struct {
	SubjectExternalSelectorValue string   `yaml:"subject_external_selector_value" json:"subject_external_selector_value"`
	Operator                     string   `yaml:"operator" json:"operator"` // IN|NOT_IN|IN_CONTAINS
	SubjectExternalValues        []string `yaml:"subject_external_values" json:"subject_external_values"`
}

type ResourceMappingDef struct {
	ID                string   `yaml:"id" json:"id"`
	AttributeValueFQN string   `yaml:"attribute_value_fqn" json:"attribute_value_fqn"`
	Terms             []string `yaml:"terms" json:"terms"`
	Group             string   `yaml:"group" json:"group"`
}

type ResourceMappingGroupDef struct {
	ID        string `yaml:"id" json:"id"`
	Namespace string `yaml:"namespace" json:"namespace"`
	Name      string `yaml:"name" json:"name"`
}

type KeyAccessServerDef struct {
	ID     string `yaml:"id" json:"id"`
	URI    string `yaml:"uri" json:"uri"`
	Name   string `yaml:"name" json:"name"`
	Source string `yaml:"source" json:"source"`
}

type KasReferenceD struct {
	ID  string `yaml:"id" json:"id"`
	URI string `yaml:"uri" json:"uri"`
}

type RegisteredResourceDef struct {
	ID        string                       `yaml:"id" json:"id"`
	Namespace string                       `yaml:"namespace" json:"namespace"`
	Name      string                       `yaml:"name" json:"name"`
	Values    []RegisteredResourceValueDef `yaml:"values" json:"values"`
}

type RegisteredResourceValueDef struct {
	ID                    string                    `yaml:"id" json:"id"`
	Value                 string                    `yaml:"value" json:"value"`
	FQN                   string                    `yaml:"fqn" json:"fqn"`
	ActionAttributeValues []ActionAttributeValueDef `yaml:"action_attribute_values" json:"action_attribute_values"`
}

// ActionAttributeValueDef binds an action taken on a registered resource value
// to the attribute value that gates that action — the edge consumed by the v2
// PDP when computing entitlements for registered resources.
type ActionAttributeValueDef struct {
	ID                string `yaml:"id" json:"id"`
	Action            string `yaml:"action" json:"action"`
	AttributeValueFQN string `yaml:"attribute_value_fqn" json:"attribute_value_fqn"`
}

type ObligationDef struct {
	ID        string               `yaml:"id" json:"id"`
	Namespace string               `yaml:"namespace" json:"namespace"`
	Name      string               `yaml:"name" json:"name"`
	Values    []ObligationValueDef `yaml:"values" json:"values"`
}

type ObligationValueDef struct {
	ID       string                 `yaml:"id" json:"id"`
	Value    string                 `yaml:"value" json:"value"`
	FQN      string                 `yaml:"fqn" json:"fqn"`
	Triggers []ObligationTriggerDef `yaml:"triggers" json:"triggers"`
}

// ObligationTriggerDef fires an obligation value when the named action is
// taken on the referenced attribute value. Optional context entries scope the
// trigger to specific PEP client IDs.
type ObligationTriggerDef struct {
	ID                string              `yaml:"id" json:"id"`
	AttributeValueFQN string              `yaml:"attribute_value_fqn" json:"attribute_value_fqn"`
	Action            string              `yaml:"action" json:"action"`
	Context           []TriggerContextDef `yaml:"context" json:"context"`
}

// TriggerContextDef scopes an obligation trigger to a specific Policy
// Enforcement Point identified by client_id.
type TriggerContextDef struct {
	PEPClientID string `yaml:"pep_client_id" json:"pep_client_id"`
}
